366:     if (!route_entry_) {
367:       return nullptr;
368:     }
369: 
370:     // Have we been called before? If so, there's no need to recompute because
371:     // by the time this method is called for the first time, route_entry_ should
372:     // not change anymore.
373:     if (metadata_match_ != nullptr) {
374:       return metadata_match_.get();
375:     }
376: 
377:     OptRef<const Protobuf::Struct> connection_metadata;
378:     const auto* downstream_conn = downstreamConnection();
379:     if (downstream_conn != nullptr) {
380:       const auto& connection_fm = downstream_conn->streamInfo().dynamicMetadata().filter_metadata();
381:       if (const auto it = connection_fm.find(Envoy::Config::MetadataFilters::get().ENVOY_LB);
382:           it != connection_fm.end()) {
383:         connection_metadata = makeOptRef<const Protobuf::Struct>(it->second);
384:       }
385:     }
386: 
387:     OptRef<const Protobuf::Struct> request_metadata;
388:     const auto& request_fm = callbacks_->streamInfo().dynamicMetadata().filter_metadata();
389:     if (const auto it = request_fm.find(Envoy::Config::MetadataFilters::get().ENVOY_LB);
390:         it != request_fm.end()) {
391:       request_metadata = makeOptRef<const Protobuf::Struct>(it->second);
392:     }
